class Solution(object):
    def bestTower(self, towers, center, radius):
        cx, cy = center
        best_q = -1
        best_pos = [-1, -1]
        for x, y, q in towers:
            if abs(x - cx) + abs(y - cy) <= radius:
                if q > best_q or (q == best_q and [x, y] < best_pos):
                    best_q = q
                    best_pos = [x, y]
        return best_pos
